import React, { useEffect, useState } from "react";

const Card = ({
  cardValue,
  cardSign,
  cardSignSwitchable,
  cardValueSwitchable,
}) => {
  const [value, setValue] = useState(cardValue);
  const [sign, setSign] = useState(cardSign);
  const [signSwitchable, setSignSwitchable] = useState(cardSignSwitchable);
  const [valueSwitchable, setValueSwitchable] = useState(cardValueSwitchable);

  const setCardValue = (number) => {
    if (number > 0 && number < 7) {
      setValue(number);
    } else if (number > -7 && number < 0) {
      setValue(number);
      setSign("negative");
    } else {
      setSignSwitchable(true);
      switch (number) {
        case 7:
          setValue(1);
          break;
        case 8:
          setValue(2);
          break;
        case 9:
          setValue(3);
          break;
        case 10:
          setValue(4);
          break;
        case 11:
          setValue(5);
          break;
        case 12:
          setValue(6);
          break;
        case 13:
          // +/- 1 or 2
          setValue(1);
          break;
        case 100:
          setValue(1);
          break;
      }
    }
  };

  const switchSign = () => {
    if (signSwitchable) {
      setValue(-value);
      if (sign === "positive") {
        setSign("negative");
      } else {
        setSign("positive");
      }
    }
  };

  // const switchOneTwo = () => {
  //   if (switchable) {
  //     if (value === 1) {
  //       setValue(2);
  //     } else if (value === 2) {
  //       setValue(1);
  //     }
  //   }
  // };

  useEffect(() => {
    setValue(setCardValue({ cardValue }));
  }, []);
  const logCard = () => {
    console.log(value);
    console.log(sign);
    console.log(signSwitchable);
    console.log(valueSwitchable);
  };

  if (signSwitchable) {
    return (
      <div className="pazaakCard">
        {/* <p className="pazaakCardNumber">{value}</p> */}
        <button onClick={logCard}>{value}</button>
      </div>
    );
  } else {
    return (
      <div className="pazaakCard">
        {/* <p className="pazaakCardNumber">{value}</p> */}
        <button onClick={logCard}>{value}</button>
      </div>
    );
  }
};

export default Card;
